// Quiet hours: no emails 9PM-8AM Eastern
const nowUTC = new Date();
const easternOffset = -4;
const easternHour = (nowUTC.getUTCHours() + easternOffset + 24) % 24;
if (easternHour >= 22 || easternHour < 7) { return []; }

const sixHoursAgo = new Date(nowUTC.getTime() - 6 * 60 * 60 * 1000);
const leads = $input.all();
const overdueLeads = leads.filter(item => {
  const d = item.json;
  const contacted = String(d.melvin_contacted).toUpperCase().trim();
  const ts = new Date(d.timestamp);
  return contacted !== "TRUE" && ts < sixHoursAgo;
});

if (overdueLeads.length === 0) { return []; }

let rows = "";
for (const lead of overdueLeads) {
  const d = lead.json;
  const h = Math.round((nowUTC - new Date(d.timestamp)) / 3600000);
  rows += "<tr><td style=\"padding:8px;border:1px solid #ddd\">" + d.name + "</td><td style=\"padding:8px;border:1px solid #ddd\">" + d.program + "</td><td style=\"padding:8px;border:1px solid #ddd\">" + d.player_age + "</td><td style=\"padding:8px;border:1px solid #ddd\"><a href=\"mailto:" + d.email + "\">" + d.email + "</a></td><td style=\"padding:8px;border:1px solid #ddd\">" + d.phone + "</td><td style=\"padding:8px;border:1px solid #ddd;font-weight:bold;color:#e74c3c\">" + h + "h ago</td></tr>";
}
const n = overdueLeads.length;
const emailSubject = "\u26a0\ufe0f " + n + " Uncontacted Lead" + (n>1?"s":"") + " \u2014 Action Needed";
const emailBody = "<div style=\"font-family:Arial,sans-serif;max-width:700px;padding:20px\"><h2 style=\"color:#e74c3c;border-bottom:2px solid #c4a24e;padding-bottom:10px\">\u26a0\ufe0f " + n + " Lead" + (n>1?"s":"") + " Waiting</h2><p>The following lead" + (n>1?"s have":" has") + " been waiting 6+ hours:</p><table style=\"width:100%;border-collapse:collapse;margin:15px 0\"><tr style=\"background:#1a1a2e;color:#fff\"><th style=\"padding:10px;text-align:left\">Name</th><th style=\"padding:10px;text-align:left\">Program</th><th style=\"padding:10px;text-align:left\">Age</th><th style=\"padding:10px;text-align:left\">Email</th><th style=\"padding:10px;text-align:left\">Phone</th><th style=\"padding:10px;text-align:left\">Waiting</th></tr>" + rows + "</table><p style=\"margin-top:20px;padding:15px;background:#fff3cd;border-left:4px solid #e74c3c\">Please reach out ASAP!</p><p style=\"color:#999;font-size:12px;margin-top:20px\">Change <strong>melvin_contacted</strong> to TRUE in the Sheet to stop reminders.</p></div>";
return [{ json: { emailBody, emailSubject } }];
